using Microsoft.AspNetCore.Mvc;
using System.IO;

namespace FileServer.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FilesController : ControllerBase
    {
        private readonly string _uploadsFolder = Path.Combine(Directory.GetCurrentDirectory(), "uploads");

        [HttpGet("{filename}")]
        public IActionResult GetFile(string filename)
        {
            var filePath = Path.Combine(_uploadsFolder, filename);

            // Check if the file exists and is within the uploads folder
            if (!Path.IsPathFullyQualified(filePath) || !filePath.StartsWith(_uploadsFolder))
            {
                return NotFound();
            }

            var fileInfo = new FileInfo(filePath);
            if (!fileInfo.Exists)
            {
                return NotFound();
            }

            var stream = new FileStream(filePath, FileMode.Open, FileAccess.Read);
            return File(stream, GetContentType(fileInfo.Extension), fileInfo.Name);
        }

        private string GetContentType(string extension)
        {
            switch (extension.ToLower())
            {
                case ".doc":
                case ".docx":
                    return "application/msword";
                case ".pdf":
                    return "application/pdf";
                case ".jpg":
                case ".jpeg":
                    return "image/jpeg";
                case ".png":
                    return "image/png";
                // Add more content types as needed
                default:
                    return "application/octet-stream";
            }
        }
    }
